/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const n = nums.length;

    // Helper function to check if index i is a peak in the current nums array
    function isPeak(arr, i) {
        const prevIndex = (i - 1 + n) % n;
        const nextIndex = (i + 1) % n;
        return arr[i] > arr[prevIndex] && arr[i] > arr[nextIndex];
    }

    // 1. Check the maximum possible number of peaks.
    // In a cycle, the maximum number of peaks is floor(n/2).
    // If k > floor(n/2), it's impossible.
    // Special case: if n=2, max peaks is 0 (since a[0] > a[1] and a[1] > a[0] is impossible).
    if (n === 2) {
        if (k > 0) return -1;
    } else {
        if (k > Math.floor(n / 2)) return -1;
    }


    // 2. Calculate the initial number of peaks
    let initialPeaks = 0;
    for (let i = 0; i < n; i++) {
        if (isPeak(nums, i)) {
            initialPeaks++;
        }
    }

    if (initialPeaks >= k) {
        return 0;
    }

    // 3. Greedy approach: Iteratively make the cheapest changes to create needed peaks.
    let neededPeaks = k - initialPeaks;
    let totalCost = 0;

    // We need to modify the array greedily.
    // Since the cost of making one index a peak depends on its neighbors, 
    // and modifying one index can affect the peak status of its neighbors,
    // a simple greedy choice based on cost per peak might be complex due to dependencies.

    // The problem constraints (N <= 5000) suggest that a dynamic programming or
    // a carefully constructed greedy approach might work, but the state space
    // of 'modifications' is too large.

    // Let's rethink the structure of peaks.
    // If we fix a set of indices S where we want peaks, the minimum cost to achieve this 
    // is found by calculating the required heights for elements in S, while ensuring 
    // neighbors are lower, and minimizing the sum of increases.

    // Since we want the *minimum* cost, and the cost is simply the total increment,
    // we should iterate over all combinations of 'neededPeaks' potential peak locations
    // and find the minimum cost configuration. This is too slow (C(N, K) * Cost).

    // Given the small N, perhaps we can simulate the process greedily by always picking 
    // the modification that costs the least to gain one required peak, updating the array, 
    // and repeating.

    // A single peak at index i requires:
    // nums[i] > nums[prev]  =>  nums[i] >= nums[prev] + 1
    // nums[i] > nums[next]  =>  nums[i] >= nums[next] + 1
    // Minimum required nums[i] = max(nums[prev], nums[next]) + 1.
    // Cost to make i a peak = max(0, required_height - original_height).

    // However, making i a peak might already require a cost if its neighbors are also modified later.
    // The crucial insight in these types of problems is often that the required height of a peak 
    // must be at least 1 greater than its neighbors *at the final state*.

    // Since we can only *increase* values, the optimal solution will likely involve setting 
    // the necessary values to just exceed their neighbors by 1.

    // Let's use a DP approach based on the indices, assuming the structure of the solution 
    // involves selecting K indices to be peaks.

    // If we select indices $i_1, i_2, \dots, i_k$ as peaks, we need:
    // $nums'[i_j] > nums'[p(i_j)]$ and $nums'[i_j] > nums'[n(i_j)]$
    // where $p$ and $n$ are the neighbors in the cycle.

    // The constraint is that $nums'[i] \ge nums[i]$.
    // Since we want to minimize $\sum (nums'[i] - nums[i])$, we should choose $nums'[i]$ minimally.

    // Due to the cycle, this is very hard to decouple.

    // Let's re-examine the constraints and the greedy approach.
    // If we greedily pick an index $i$ that is *not* a peak, calculate the cost to make it a peak *in the current state*,
    // add this cost, update nums[i], and increment the peak count. Repeat $k - initialPeaks$ times.

    // This greedy strategy might fail because increasing $nums[i]$ might make a neighbor $j$ *not* a peak, 
    // or might require even more to make $j$ a peak later.

    // However, since the problem asks for the minimum cost, and the cost is additive, 
    // and we are only increasing values, the relative order of neighbors only changes if we increase them.

    // Let's assume the simple iterative greedy approach works for now, as it's the most plausible
    // path for competitive programming unless DP is obvious.

    let currentNums = [...nums];
    let currentPeaks = initialPeaks;
    let cost = 0;

    while (currentPeaks < k) {
        let bestCostForNextPeak = Infinity;
        let bestIndexToModify = -1;
        let potentialNewNums = null;

        // Iterate over all non-peak indices to find the minimum cost to turn *one* into a peak
        for (let i = 0; i < n; i++) {
            if (isPeak(currentNums, i)) continue;

            const prevIndex = (i - 1 + n) % n;
            const nextIndex = (i + 1) % n;

            // Calculate the required value for currentNums[i]
            const requiredHeight = Math.max(currentNums[prevIndex], currentNums[nextIndex]) + 1;

            // Calculate the cost to achieve this height
            const costToMakePeak = Math.max(0, requiredHeight - currentNums[i]);

            if (costToMakePeak < bestCostForNextPeak) {
                bestCostForNextPeak = costToMakePeak;
                bestIndexToModify = i;

                // Store the resulting state temporarily
                potentialNewNums = [...currentNums];
                potentialNewNums[i] = requiredHeight;
            }
        }

        if (bestIndexToModify === -1) {
            // This should not happen if k <= floor(n/2) and the initial check passed,
            // unless all remaining non-peaks require infinite cost (which is impossible here).
            // If we reach here, it implies we cannot create more peaks, contradicting the initial check.
            return -1; 
        }

        // Apply the best modification found
        cost += bestCostForNextPeak;
        currentNums = potentialNewNums;

        // Crucially, we must recount peaks because modifying one element might affect neighbors
        // (e.g., making i a peak might make neighbor j NOT a peak, or make j become a peak if it wasn't before).

        let newPeaks = 0;
        for(let i = 0; i < n; i++) {
            if (isPeak(currentNums, i)) {
                newPeaks++;
            }
        }

        // Check if the greedy step actually increased the peak count by at least 1, 
        // or if it led to a state where the required number is impossible.
        if (newPeaks <= currentPeaks) {
            // This means the minimal change we made (bestCostForNextPeak) did not result 
            // in an increase of the peak count, or the count decreased/stagnated.
            // In a true greedy sense, we should discard this path or realize the greedy choice failed.
            // Given the problem structure, if the count stagnates before k, it's impossible via this path.
            // Since we are minimizing cost, if the best move doesn't help, we assume failure for this path.
            return -1;
        }

        currentPeaks = newPeaks;
    }

    return cost;
}

