// Function to check if index i is a peak in the current array arr
fn is_peak(arr : Array(Int64), n : Int64, i : Int64) : Bool
    let prev_index = (i - 1 + n) % n
    let next_index = (i + 1) % n
    arr[i] > arr[prev_index] && arr[i] > arr[next_index]

// Function to count the number of peaks in the array
fn count_peaks(arr : Array(Int64), n : Int64) : Int64
    var count = 0 as Int64
    for i in 0..<n
        if is_peak(arr, n, i.to_int64)
            count += 1
    count

// Main solving function
fn solve(nums : Array(Int64), k : Int64) : Int64
    let n_int = nums.size
    let n = n_int.to_int64()

    // 1. Maximum possible peaks check
    if n == 2
        if k > 0
            return -1
    else
        if k > n / 2
            return -1

    // 2. Initial peak count
    let initial_peaks = count_peaks(nums, n)

    if initial_peaks >= k
        return 0

    // 3. Iterative Greedy Approach
    var current_nums = nums.dup
    var current_peaks = initial_peaks
    var total_cost = 0 as Int64

    while current_peaks < k
        var best_cost_for_next_peak = Int64.infinity
        var best_index_to_modify = -1 as Int64
        var potential_new_nums : Array(Int64) = nil

        // Iterate over all indices to find the minimum cost to *ensure* a peak is created or maintained
        // We check all indices because a neighbor might become a peak after an increment, 
        // but the greedy choice should focus on the minimal cost to push the count up.
        for i in 0..<n_int
            let i_int64 = i.to_int64()
            if is_peak(current_nums, n, i_int64)
                next # continue

            let prev_index = (i_int64 - 1 + n) % n
            let next_index = (i_int64 + 1) % n

            // Calculate the required value for current_nums[i] to be a peak in the current state
            let required_height = (current_nums[prev_index] > current_nums[next_index] ? current_nums[prev_index] : current_nums[next_index]) + 1

            // Calculate the cost to achieve this height
            let cost_to_make_peak = (required_height > current_nums[i_int64] ? required_height - current_nums[i_int64] : 0)

            if cost_to_make_peak < best_cost_for_next_peak
                best_cost_for_next_peak = cost_to_make_peak
                best_index_to_modify = i_int64

                // Store the resulting state temporarily
                potential_new_nums = current_nums.dup
                potential_new_nums[i] = required_height

        if best_index_to_modify == -1s
            // Should not happen if k <= n/2, but as a safeguard
            return -1

        // Apply the best modification found
        total_cost += best_cost_for_next_peak
        current_nums = potential_new_nums

        // Recount peaks after modification
        let new_peaks = count_peaks(current_nums, n)

        // If the best move did not increase the peak count, we are stuck/failed
        if new_peaks <= current_peaks
            return -1

        current_peaks = new_peaks

    return total_cost
